@GwtCompatible(serializable = true, emulated = true)
public final class LinkedListMultimap<K, V>
    implements ListMultimap<K, V>, Serializable {
private class NodeIterator implements ListIterator<Node<K, V>> {
    int nextIndex;
    Node<K, V> next;
    Node<K, V> current;
    Node<K, V> previous;
    NodeIterator() {
      next = head;
    }
    NodeIterator(int index) {
      int size = size();
      Preconditions.checkPositionIndex(index, size);
      if (index >= (size / 2)) {
        previous = tail;
        nextIndex = size;
        while (index++ < size) {
          previous();
        }
      } else {
        next = head;
        while (index-- > 0) {
          next();
        }
      }
      current = null;
    }
    @Override
    public boolean hasNext() {
      return next != null;
    }
    @Override
    public Node<K, V> next() {
      checkElement(next);
      previous = current = next;
      next = next.next;
      nextIndex++;
      return current;
    }
    @Override
    public void remove() {
      checkState(current != null);
      if (current != next) {
        previous = current.previous;
        nextIndex--;
      } else {
        next = current.next;
      }
      removeNode(current);
      current = null;
    }
    @Override
    public boolean hasPrevious() {
      return previous != null;
    }
    @Override
    public Node<K, V> previous() {
      checkElement(previous);
      next = current = previous;
      previous = previous.previous;
      nextIndex--;
      return current;
    }
    @Override
    public int nextIndex() {
      return nextIndex;
    }
    @Override
    public int previousIndex() {
      return nextIndex - 1;
    }
    @Override
    public void set(Node<K, V> e) {
      throw new UnsupportedOperationException();
    }
    @Override
    public void add(Node<K, V> e) {
      throw new UnsupportedOperationException();
    }
    void setValue(V value) {
      checkState(current != null);
      current.value = value;
    }
  }

private transient List<V> valuesList;

@Override
  public List<V> values() {
    List<V> result = valuesList;
    if (result == null) {
      valuesList = result = new AbstractSequentialList<V>() {
        @Override public int size() {
          return keyCount.size();
        }
        @Override
        public ListIterator<V> listIterator(int index) {
          final NodeIterator nodes = new NodeIterator(index);
          return new ListIterator<V>() {
            @Override
            public boolean hasNext() {
              return nodes.hasNext();
            }
            @Override
            public V next() {
              return nodes.next().value;
            }
            @Override
            public boolean hasPrevious() {
              return nodes.hasPrevious();
            }
            @Override
            public V previous() {
              return nodes.previous().value;
            }
            @Override
            public int nextIndex() {
              return nodes.nextIndex();
            }
            @Override
            public int previousIndex() {
              return nodes.previousIndex();
            }
            @Override
            public void remove() {
              nodes.remove();
            }
            @Override
            public void set(V e) {
              nodes.setValue(e);
            }
            @Override
            public void add(V e) {
              throw new UnsupportedOperationException();
            }
          };
        }
      };
    }
    return result;
  }

private static <K, V> Entry<K, V> createEntry(final Node<K, V> node) {
    return new AbstractMapEntry<K, V>() {
      @Override public K getKey() {
        return node.key;
      }
      @Override public V getValue() {
        return node.value;
      }
      @Override public V setValue(V value) {
        V oldValue = node.value;
        node.value = value;
        return oldValue;
      }
    };
  }

private transient List<Entry<K, V>> entries;

@Override
  public List<Entry<K, V>> entries() {
    List<Entry<K, V>> result = entries;
    if (result == null) {
      entries = result = new AbstractSequentialList<Entry<K, V>>() {
        @Override public int size() {
          return keyCount.size();
        }
        @Override public ListIterator<Entry<K, V>> listIterator(int index) {
          final ListIterator<Node<K, V>> nodes = new NodeIterator(index);
          return new ListIterator<Entry<K, V>>() {
            @Override
            public boolean hasNext() {
              return nodes.hasNext();
            }
            @Override
            public Entry<K, V> next() {
              return createEntry(nodes.next());
            }
            @Override
            public void remove() {
              nodes.remove();
            }
            @Override
            public boolean hasPrevious() {
              return nodes.hasPrevious();
            }
            @Override
